  wishOwnerControlDesc: { en: "You can make changes or delete this wish card at any time.", es: "Puedes editar o eliminar esta tarjeta en cualquier momento.", fr: "Vous pouvez modifier ou supprimer cette carte à tout moment.", ar: "يمكنك التعديل أو الحذف في أي وقت.", hi: "आप इस कार्ड को कभी भी बदल या हटा सकते हैं।", zh: "您可以随时修改或删除此卡片。", pt: "Você pode editar ou excluir este cartão a qualquer momento.", ru: "Вы можете изменить или удалить эту открытку в любое время.", de: "Sie können diese Karte jederzeit bearbeiten oder löschen.", ja: "このカードはいつでも編集または削除できます。", ko: "언제든지 이 카드를 수정하거나 삭제할 수 있습니다.", it: "Puoi modificare o eliminare questa cartolina in qualsiasi momento.", tr: "Bu kartı istediğiniz zaman düzenleyebilir veya silebilirsiniz.", id: "Anda dapat mengedit atau menghapus kartu ini kapan saja.", ur: "آپ اس وش کارڈ کو کسی بھی وقت تبدیل یا ختم کر سکتے ہیں۔", bn: "আপনি যেকোনো সময় এই কার্ড পরিবর্তন বা মুছে ফেলতে পারেন।", vi: "Bạn có thể chỉnh sửa hoặc xóa thiệp này bất kỳ lúc nào.", sw: "Unaweza kubadilisha au kufuta kadi hii wakati wowote." },
  cardzyWatermarkCTA: { en: "Made with Cardzy.online — Create Yours Free", es: "Creado con Cardzy.online — Crea la tuya gratis", fr: "Créé avec Cardzy.online — Créez la vôtre gratuitement", ar: "تم الإنشاء بواسطة Cardzy.online — أنشئ بطاقتك مجاناً", hi: "Cardzy.online द्वारा बनाया गया — अपना मुफ़्त बनाएं", zh: "由 Cardzy.online 制作 — 免费创建您的卡片", pt: "Criado com Cardzy.online — Crie o seu grátis", ru: "Создано на Cardzy.online — Создайте свою бесплатно", de: "Erstellt mit Cardzy.online — Erstellen Sie Ihre kostenlos", ja: "Cardzy.onlineで作成 — 無料で作成", ko: "Cardzy.online으로 제작 — 무료로 만드세요", it: "Creato con Cardzy.online — Crea la tua gratis", tr: "Cardzy.online ile yapıldı — Ücretsiz Oluşturun", id: "Dibuat dengan Cardzy.online — Buat Milik Anda Gratis", ur: "کارڈزی آن لائن پر بنایا گیا — اپنا کارڈ بالکل مفت بنائیں", bn: "Cardzy.online এ তৈরি — বিনামূল্যে তৈরি করুন", vi: "Được tạo bằng Cardzy.online — Tạo thiệp miễn phí", sw: "Imetengenezwa na Cardzy.online — Unda yako bure" },
