interface LangCtx {
  lang: LangCode
  setLang: (l: LangCode) => void
  t: (key: keyof typeof T) => string
}

const LanguageContext = createContext<LangCtx>({
  lang: 'en',
  setLang: () => {},
  t: (key) => T[key]?.en ?? '',
})

export function LanguageProvider({ children }: { children: React.ReactNode }) {
  const [lang, setLangState] = useState<LangCode>('en')

  // Load language from localStorage after mount
  useEffect(() => {
    const saved = localStorage.getItem('cardzy_lang') as LangCode
    if (saved && LANGUAGES.some((l) => l.code === saved)) {
      setLangState(saved)
    } else {
      const browserLang = navigator.language.split('-')[0] as LangCode
      if (LANGUAGES.some((l) => l.code === browserLang)) {
        setLangState(browserLang)
      }
    }
  }, [])

  // Sync to localStorage and set HTML direction/attributes
  useEffect(() => {
    localStorage.setItem('cardzy_lang', lang)
    document.documentElement.lang = lang
    document.documentElement.dir = (lang === 'ur' || lang === 'ar') ? 'rtl' : 'ltr'
  }, [lang])

  const setLang = (l: LangCode) => {
    setLangState(l)
  }

  const t = (key: string) => {
    const entry = (T as any)[key] || (EXTRA_T as any)[key]
    if (!entry) return ''
    return entry[lang] ?? entry.en ?? ''
  }

  return (
    <LanguageContext.Provider value={{ lang, setLang, t: t as any }}>
      {children}
    </LanguageContext.Provider>
  )
}

export function useLang() {
  return useContext(LanguageContext)
}
